public class ConnectionPool {
    private static volatile ConnectionPool instance;
    private final int poolSize;
    private int activeConnections = 0;

    private ConnectionPool(int poolSize) {
        this.poolSize = poolSize;
        System.out.println("ConnectionPool created with size: " + poolSize);
    }

    public static ConnectionPool getInstance() {
        if (instance == null) {
            synchronized (ConnectionPool.class) {
                if (instance == null) {
                    instance = new ConnectionPool(10);
                }
            }
        }
        return instance;
    }

    public synchronized boolean getConnection() {
        if (activeConnections < poolSize) {
            activeConnections++;
            System.out.println("Connection granted. Active: " + activeConnections);
            return true;
        }
        System.out.println("Pool exhausted!");
        return false;
    }

    public synchronized void releaseConnection() {
        if (activeConnections > 0) {
            activeConnections--;
            System.out.println("Connection released. Active: " + activeConnections);
        }
    }

    public static void main(String[] args) {
        ConnectionPool pool1 = ConnectionPool.getInstance();
        ConnectionPool pool2 = ConnectionPool.getInstance();
        System.out.println("Same instance: " + (pool1 == pool2));

        pool1.getConnection();
        pool1.getConnection();
        pool2.releaseConnection(); // same object as pool1
    }
}

