public class HttpRequest {
    private final String method;
    private final String url;
    private final String body;
    private final java.util.Map<String, String> headers;
    private final int timeout;

    private HttpRequest(Builder builder) {
        this.method = builder.method;
        this.url = builder.url;
        this.body = builder.body;
        this.headers = builder.headers;
        this.timeout = builder.timeout;
    }

    @Override
    public String toString() {
        return method + " " + url + "\nHeaders: " + headers
            + "\nBody: " + (body != null ? body : "(none)")
            + "\nTimeout: " + timeout + "ms";
    }

    public static class Builder {
        private final String method;
        private final String url;
        private String body;
        private java.util.Map<String, String> headers = new java.util.HashMap<>();
        private int timeout = 5000;

        public Builder(String method, String url) {
            this.method = method;
            this.url = url;
        }

        public Builder body(String body) { this.body = body; return this; }
        public Builder header(String key, String value) {
            this.headers.put(key, value); return this;
        }
        public Builder timeout(int ms) { this.timeout = ms; return this; }

        public HttpRequest build() { return new HttpRequest(this); }
    }

    public static void main(String[] args) {
        HttpRequest get = new HttpRequest.Builder("GET", "/api/students")
            .header("Accept", "application/json")
            .header("Authorization", "Bearer token123")
            .timeout(3000)
            .build();
        System.out.println(get);

        System.out.println();

        HttpRequest post = new HttpRequest.Builder("POST", "/api/students")
            .header("Content-Type", "application/json")
            .body("{\"name\": \"Arjun\", \"marks\": 85}")
            .build();
        System.out.println(post);
    }
}

