import java.util.ArrayList;
import java.util.List;

interface StockObserver {
    void onPriceChange(String stock, double oldPrice, double newPrice);
}

class StockMarket {
    private final List<StockObserver> observers = new ArrayList<>();
    private final java.util.Map<String, Double> prices = new java.util.HashMap<>();

    public void subscribe(StockObserver observer) {
        observers.add(observer);
    }

    public void unsubscribe(StockObserver observer) {
        observers.remove(observer);
    }

    public void updatePrice(String stock, double newPrice) {
        double oldPrice = prices.getOrDefault(stock, 0.0);
        prices.put(stock, newPrice);
        for (StockObserver observer : observers) {
            observer.onPriceChange(stock, oldPrice, newPrice);
        }
    }
}

class PriceDisplay implements StockObserver {
    private String name;
    PriceDisplay(String name) { this.name = name; }

    public void onPriceChange(String stock, double oldPrice, double newPrice) {
        String direction = newPrice > oldPrice ? "UP" : "DOWN";
        System.out.printf("%s: %s %.2f -> %.2f (%s)%n",
                          name, stock, oldPrice, newPrice, direction);
    }
}

class AlertSystem implements StockObserver {
    private double threshold;
    AlertSystem(double threshold) { this.threshold = threshold; }

    public void onPriceChange(String stock, double oldPrice, double newPrice) {
        double change = Math.abs(newPrice - oldPrice) / Math.max(oldPrice, 0.01) * 100;
        if (change > threshold) {
            System.out.printf("ALERT: %s moved %.1f%% (threshold: %.1f%%)%n",
                              stock, change, threshold);
        }
    }
}

public class ObserverDemo {
    public static void main(String[] args) {
        StockMarket market = new StockMarket();
        market.subscribe(new PriceDisplay("Display-1"));
        market.subscribe(new AlertSystem(5.0));

        market.updatePrice("TCS", 3500.0);
        System.out.println();
        market.updatePrice("TCS", 3700.0);  // ~5.7% change -> triggers alert
    }
}

interface PaymentStrategy {
    boolean pay(double amount);
    String getName();
}

class CreditCardPayment implements PaymentStrategy {
    private String cardNumber;
    CreditCardPayment(String cardNumber) { this.cardNumber = cardNumber; }

    public boolean pay(double amount) {
        String masked = "****" + cardNumber.substring(cardNumber.length() - 4);
        System.out.printf("Paid %.2f via Credit Card %s%n", amount, masked);
        return true;
    }
    public String getName() { return "Credit Card"; }
}

class UPIPayment implements PaymentStrategy {
    private String upiId;
    UPIPayment(String upiId) { this.upiId = upiId; }

    public boolean pay(double amount) {
        System.out.printf("Paid %.2f via UPI %s%n", amount, upiId);
        return true;
    }
    public String getName() { return "UPI"; }
}

class WalletPayment implements PaymentStrategy {
    private double balance;
    WalletPayment(double balance) { this.balance = balance; }

    public boolean pay(double amount) {
        if (balance >= amount) {
            balance -= amount;
            System.out.printf("Paid %.2f via Wallet. Remaining: %.2f%n", amount, balance);
            return true;
        }
        System.out.println("Wallet: insufficient balance!");
        return false;
    }
    public String getName() { return "Wallet"; }
}

class ShoppingCart {
    private PaymentStrategy paymentStrategy;

    public void setPaymentStrategy(PaymentStrategy strategy) {
        this.paymentStrategy = strategy;
        System.out.println("Payment method set to: " + strategy.getName());
    }

    public void checkout(double amount) {
        if (paymentStrategy == null) {
            System.out.println("No payment method selected!");
            return;
        }
        paymentStrategy.pay(amount);
    }
}

public class StrategyDemo {
    public static void main(String[] args) {
        ShoppingCart cart = new ShoppingCart();

        cart.setPaymentStrategy(new CreditCardPayment("4111222233334444"));
        cart.checkout(1500.00);

        System.out.println();
        cart.setPaymentStrategy(new UPIPayment("arjun@upi"));
        cart.checkout(750.00);

        System.out.println();
        cart.setPaymentStrategy(new WalletPayment(500.00));
        cart.checkout(300.00);
        cart.checkout(300.00); // insufficient balance
    }
}

